import React from 'react';
import { Link } from 'react-router-dom';

const CategoryGrid = ({ categories }) => (
  <section className="py-8 md:py-12 bg-white">
    <div className="container mx-auto px-4">
      <h2 className="text-2xl md:text-3xl font-bold text-gray-900 mb-8 md:mb-10 text-center">
        Shop by Room
      </h2>
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-6 md:gap-8">
        {categories.map((cat) => (
          <Link
            to={`/category/${cat.slug}`}
            key={cat.id}
            className="group flex flex-col items-center"
          >
            <div className="w-32 h-32 md:w-40 md:h-40 rounded-full overflow-hidden bg-gray-100 shadow-sm group-hover:shadow-lg transition-shadow mb-4 border-4 border-transparent group-hover:border-primary-100">
              <img
                src={cat.image}
                alt={cat.name}
                className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                loading="lazy"
              />
            </div>
            <span className="text-gray-800 font-semibold text-sm md:text-base text-center group-hover:text-brand-orange transition">
              {cat.name}
            </span>
          </Link>
        ))}
      </div>
    </div>
  </section>
);

export default CategoryGrid;
